arguments.file_text:
namespace sv_b553709f4a594fe68f25daaac2e02eed.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_b553709f4a594fe68f25daaac2e02eed.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Team Chat</PageTitle>

<div class="chat-app">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="chat-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <main class="chat-main @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="main-header">
                <h2># @_activeChannel.Name</h2>
                <span class="main-header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-header">
                                <span class="msg-author">@msg.Author</span>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var reaction in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => ReactAsync(msg.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter link *@
                            @if (_threadSummaries.TryGetValue(msg.Id, out var summary))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    &middot; Last @FormatRelativeTime(summary.LastReplyAt)
                                </button>
                            }

                            @* Hover action buttons *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg.Id)">
                                        💬 Reply
                                    </button>
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">
                                        😀 React
                                    </button>
                                </div>

                                @if (_emojiPickerMessageId == msg.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in _commonEmojis)
                                        {
                                            <button class="emoji-btn" @onclick="() => ReactAsync(msg.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Type a message…"
                          @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="OnMainKeyDown" />
                <button class="send-btn" @onclick="SendMainMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* ── Right Panel: Thread View ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="msg-author">@_threadRootMessage.Author</span>
                <span class="msg-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <div class="msg-content">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-replies" @ref="_threadListRef">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-row thread-reply">
                            <div class="message-header">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => ReactAsync(reply.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Reply in thread…"
                          @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _messageSkip;
    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private string _newMessageText = "";

    // Thread state
    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _threadReplyText = "";

    // Thread summaries keyed by root message id
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    // Hover / emoji picker state
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    // Element references for scroll handling
    private ElementReference _messageListRef;
    private ElementReference _threadListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messageSkip = 0;
        _allMessagesLoaded = false;
        _messages = null;
        _threadSummaries.Clear();
        _emojiPickerMessageId = null;

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _messageSkip = messages.Count;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        UpdateChannelUnread(channel.Id);

        await ScrollToBottomAsync();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_activeChannelId is null || _loadingMore || _allMessagesLoaded) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messageSkip, PageSize);
        if (older.Count == 0)
        {
            _allMessagesLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            BuildThreadSummaries();
        }

        _loadingMore = false;
    }

    private async Task SendMainMessageAsync()
    {
        if (_activeChannelId is null || string.IsNullOrWhiteSpace(_newMessageText)) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _messageSkip++;
        _newMessageText = "";

        await ScrollToBottomAsync();
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);
        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
        _emojiPickerMessageId = null;

        await ScrollThreadToBottomAsync();
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadMessages = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (_threadRootId is null || _activeChannelId is null || string.IsNullOrWhiteSpace(_threadReplyText)) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootId);
        _threadMessages ??= [];
        _threadMessages.Add(reply);
        _threadReplyText = "";

        // Update thread summary in main view
        if (_threadSummaries.ContainsKey(_threadRootId.Value))
        {
            var existing = _threadSummaries[_threadRootId.Value];
            _threadSummaries[_threadRootId.Value] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootId.Value] = new ThreadSummary(_threadRootId.Value, 1, reply.SentAt);
        }

        await ScrollThreadToBottomAsync();
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Optimistic UI update for main messages
        if (_messages is not null)
        {
            var idx = _messages.FindIndex(m => m.Id == messageId);
            if (idx >= 0)
            {
                _messages[idx] = AddReactionToMessage(_messages[idx], emoji);
            }
        }

        // Optimistic UI update for thread messages
        if (_threadMessages is not null)
        {
            var idx = _threadMessages.FindIndex(m => m.Id == messageId);
            if (idx >= 0)
            {
                _threadMessages[idx] = AddReactionToMessage(_threadMessages[idx], emoji);
            }
        }
    }

    private static Message AddReactionToMessage(Message msg, string emoji)
    {
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            var users = existing.Users.ToList();
            users.Add("You");
            reactions[reactions.IndexOf(existing)] = existing with { Users = users };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }
        return msg with { Reactions = reactions };
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);

        foreach (var g in grouped)
        {
            _threadSummaries[g.Key] = new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt));
        }
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task OnMessageListScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
