    private ElementReference _threadListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messageSkip = 0;
        _allMessagesLoaded = false;
        _messages = null;
        _threadSummaries.Clear();
        _emojiPickerMessageId = null;

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _messageSkip = messages.Count;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        UpdateChannelUnread(channel.Id);

        await ScrollToBottomAsync();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_activeChannelId is null || _loadingMore || _allMessagesLoaded) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messageSkip, PageSize);
        if (older.Count == 0)
        {
            _allMessagesLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            BuildThreadSummaries();
        }

        _loadingMore = false;
    }

    private async Task SendMainMessageAsync()
    {
        if (_activeChannelId is null || string.IsNullOrWhiteSpace(_newMessageText)) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _messageSkip++;
        _newMessageText = "";

        await ScrollToBottomAsync();
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);
        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
        _emojiPickerMessageId = null;

        await ScrollThreadToBottomAsync();
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadMessages = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (_threadRootId is null || _activeChannelId is null || string.IsNullOrWhiteSpace(_threadReplyText)) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootId);
        _threadMessages ??= [];
        _threadMessages.Add(reply);
        _threadReplyText = "";

        // Update thread summary in main view
        if (_threadSummaries.ContainsKey(_threadRootId.Value))
        {
            var existing = _threadSummaries[_threadRootId.Value];
            _threadSummaries[_threadRootId.Value] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootId.Value] = new ThreadSummary(_threadRootId.Value, 1, reply.SentAt);
        }

        await ScrollThreadToBottomAsync();
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Optimistic UI update for main messages
        if (_messages is not null)
        {
            var idx = _messages.FindIndex(m => m.Id == messageId);
            if (idx >= 0)
            {
                _messages[idx] = AddReactionToMessage(_messages[idx], emoji);
            }
        }

        // Optimistic UI update for thread messages
        if (_threadMessages is not null)
        {
            var idx = _threadMessages.FindIndex(m => m.Id == messageId);
            if (idx >= 0)
            {
                _threadMessages[idx] = AddReactionToMessage(_threadMessages[idx], emoji);
            }
        }
    }

    private static Message AddReactionToMessage(Message msg, string emoji)
    {
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            var users = existing.Users.ToList();
            users.Add("You");
            reactions[reactions.IndexOf(existing)] = existing with { Users = users };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }
        return msg with { Reactions = reactions };
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);

        foreach (var g in grouped)
        {
            _threadSummaries[g.Key] = new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt));
        }
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
