+                _messages[idx] = AddReactionToMessage(_messages[idx], emoji);
+            }
+        }
+
+        // Optimistic UI update for thread messages
+        if (_threadMessages is not null)
+        {
+            var idx = _threadMessages.FindIndex(m => m.Id == messageId);
+            if (idx >= 0)
+            {
+                _threadMessages[idx] = AddReactionToMessage(_threadMessages[idx], emoji);
+            }
+        }
+    }
+
+    private static Message AddReactionToMessage(Message msg, string emoji)
+    {
+        var reactions = msg.Reactions.ToList();
+        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
+        if (existing is not null)
+        {
+            var users = existing.Users.ToList();
+            users.Add("You");
+            reactions[reactions.IndexOf(existing)] = existing with { Users = users };
+        }
+        else
+        {
+            reactions.Add(new Reaction(emoji, ["You"]));
+        }
+        return msg with { Reactions = reactions };
+    }
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    private void BuildThreadSummaries()
+    {
+        if (_messages is null) return;
+
+        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
+        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);
+
+        foreach (var g in grouped)
+        {
+            _threadSummaries[g.Key] = new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt));
+        }
+    }
+
+    private void UpdateChannelUnread(int channelId)
+    {
+        if (_channels is null) return;
+        var idx = _channels.FindIndex(c => c.Id == channelId);
+        if (idx >= 0)
+        {
+            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
+        }
+    }
+
+    private async Task OnMessageListScroll()
+    {
+        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
+        if (scrollTop < 50)
+        {
+            await LoadOlderMessagesAsync();
+        }
+    }
+
+    private async Task OnMainKeyDown(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendMainMessageAsync();
+        }
+    }
+
+    private async Task OnThreadKeyDown(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    private async Task ScrollToBottomAsync()
+    {
+        await Task.Yield();
+        try
+        {
+            await JS.InvokeVoidAsync("eval",
+                "document.querySelector('.message-list')?.scrollTo(0, document.querySelector('.message-list').scrollHeight)");
+        }
+        catch { }
+    }
+
+    private async Task ScrollThreadToBottomAsync()
+    {
+        await Task.Yield();
+        try
+        {
+            await JS.InvokeVoidAsync("eval",
+                "document.querySelector('.thread-replies')?.scrollTo(0, document.querySelector('.thread-replies').scrollHeight)");
+        }
+        catch { }
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt;
+        if (diff.TotalSeconds < 60) return "just now";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
+        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
+        return sentAt.ToString("MMM d, yyyy");
+    }
+
+    private static string TruncateDescription(string desc)
+    {
+        if (string.IsNullOrEmpty(desc)) return "";
+        return desc.Length > 40 ? desc[..37] + "…" : desc;
+    }
+}
