.chat-app {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    color: #1d1c1d;
}

/* ── Sidebar ── */
.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #fff;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #522653;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 8px;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 4px;
    transition: background 0.15s;
    position: relative;
}

.channel-item:hover {
    background: rgba(255,255,255,0.1);
}

.channel-item.active {
    background: #1164a3;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: rgba(255,255,255,0.6);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    position: absolute;
    right: 10px;
    top: 8px;
}

/* ── Main Area ── */
.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
}

.chat-main.thread-open {
    max-width: 55%;
}

.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.main-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
}

.main-header-desc {
    font-size: 0.85rem;
    color: #616061;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 10px;
    font-size: 0.85rem;
    color: #888;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1.1rem;
}

/* ── Messages ── */
.message-row {
    padding: 6px 8px;
    border-radius: 6px;
    position: relative;
    margin-bottom: 2px;
}

.message-row:hover {
    background: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.msg-author {
    font-weight: 700;
    font-size: 0.95rem;
}

.msg-time {
    font-size: 0.75rem;
    color: #888;
}

.msg-content {
    font-size: 0.93rem;
    line-height: 1.45;
    margin-top: 2px;
    white-space: pre-wrap;
    word-break: break-word;
}

/* Reactions */
.reactions-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #e0e8f0;
    border-color: #1164a3;
}

/* Thread link */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

/* Hover actions */
.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
}

/* Emoji picker */
.emoji-picker {
    position: absolute;
    top: -4px;
    right: 8px;
    transform: translateY(-100%);
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.3rem;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

/* ── Message Input ── */
.message-input-area {
    padding: 10px 20px 14px;
    border-top: 1px solid #e0e0e0;
    display: flex;
    gap: 8px;
    align-items: flex-end;
    flex-shrink: 0;
}

.message-input {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input:focus {
    border-color: #1164a3;
}

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 8px 18px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #005e46;
}

.send-btn:disabled {
    background: #ccc;
    cursor: not-allowed;
}

/* ── Thread Panel ── */
.chat-thread-panel {
